message:
style(core): cargo fmt tidy on begin_pager_txn_with_busy_timeout call

cargo fmt moved the `let mut txn = match …` binding back to the one-
line form with the match value on the indented continuation:

    let mut txn =
        match self.begin_pager_txn_with_busy_timeout(&self.pager, cx, mode, is_concurrent) {
            Ok(txn) => txn,
            Err(error) => { … }
        };

vs the previous four-arg-per-line call-site. No semantic change.

files.patch:
@@ -24926,18 +24926,14 @@ impl Connection {
         } else {
             None
         };
-        let mut txn = match self.begin_pager_txn_with_busy_timeout(
-            &self.pager,
-            cx,
-            mode,
-            is_concurrent,
-        ) {
-            Ok(txn) => txn,
-            Err(error) => {
-                record_hot_path_duration(&FSQLITE_BEGIN_SETUP_TIME_NS, begin_setup_start);
-                return Err(error);
-            }
-        };
+        let mut txn =
+            match self.begin_pager_txn_with_busy_timeout(&self.pager, cx, mode, is_concurrent) {
+                Ok(txn) => txn,
